// 改进的Markdown解析器
const marked = {
  parse: function(markdown) {
    // 转义HTML
    function escapeHtml(text) {
      const map = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#039;'
      };
      return text.replace(/[&<>"']/g, m => map[m]);
    }

    // 存储代码块和行内代码
    const codeBlocks = [];
    const inlineCodes = [];

    // 1. 先提取所有代码块（三个反引号）
    let html = markdown.replace(/```([^\n]*)\n([\s\S]*?)```/g, (match, lang, code) => {
      const index = codeBlocks.length;
      codeBlocks.push({
        lang: lang.trim(),
        code: code
      });
      // 使用特殊的HTML注释作为占位符，不会被段落处理
      return `\n<!--CODEBLOCK:${index}-->\n`;
    });

    // 2. 提取行内代码（单个反引号）
    html = html.replace(/`([^`\n]+)`/g, (match, code) => {
      const index = inlineCodes.length;
      inlineCodes.push(code);
      return `<!--INLINECODE:${index}-->`;
    });

    // 3. 处理标题 (# ## ### ...)
    html = html.replace(/^######\s+(.+)$/gm, '<h6>$1</h6>');
    html = html.replace(/^#####\s+(.+)$/gm, '<h5>$1</h5>');
    html = html.replace(/^####\s+(.+)$/gm, '<h4>$1</h4>');
    html = html.replace(/^###\s+(.+)$/gm, '<h3>$1</h3>');
    html = html.replace(/^##\s+(.+)$/gm, '<h2>$1</h2>');
    html = html.replace(/^#\s+(.+)$/gm, '<h1>$1</h1>');

    // 4. 处理水平线 (必须在列表之前)
    html = html.replace(/^(---|\*\*\*|___)\s*$/gm, '<hr>');

    // 5. 处理粗体和斜体
    html = html.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    html = html.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>');
    html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    html = html.replace(/__(.+?)__/g, '<strong>$1</strong>');
    html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');
    html = html.replace(/_(.+?)_/g, '<em>$1</em>');

    // 6. 处理删除线
    html = html.replace(/~~(.+?)~~/g, '<del>$1</del>');

    // 7. 处理图片（必须在链接之前）
    html = html.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />');

    // 8. 处理链接
    html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');

    // 9. 处理引用
    html = html.replace(/^>\s+(.+)$/gm, '<blockquote>$1</blockquote>');
    // 合并连续的引用
    html = html.replace(/(<\/blockquote>\n<blockquote>)/g, '\n');

    // 10. 处理表格
    html = html.replace(/\|(.+)\|\n\|[-:\s|]+\|\n((?:\|.+\|\n?)+)/g, (match, header, rows) => {
      const headers = header.split('|').filter(h => h.trim()).map(h => `<th>${h.trim()}</th>`).join('');
      const rowsHtml = rows.trim().split('\n').map(row => {
        const cells = row.split('|').filter(c => c.trim()).map(c => `<td>${c.trim()}</td>`).join('');
        return `<tr>${cells}</tr>`;
      }).join('');
      return `<table><thead><tr>${headers}</tr></thead><tbody>${rowsHtml}</tbody></table>`;
    });

    // 11. 处理列表
    const lines = html.split('\n');
    const processed = [];
    let inList = false;
    let listType = null;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const trimmed = line.trim();

      // 无序列表
      if (trimmed.match(/^[\*\-\+]\s+(.+)$/)) {
        const content = trimmed.replace(/^[\*\-\+]\s+/, '');
        if (!inList || listType !== 'ul') {
          if (inList) processed.push(`</${listType}>`);
          processed.push('<ul>');
          listType = 'ul';
          inList = true;
        }
        processed.push(`<li>${content}</li>`);
      }
      // 有序列表
      else if (trimmed.match(/^\d+\.\s+(.+)$/)) {
        const content = trimmed.replace(/^\d+\.\s+/, '');
        if (!inList || listType !== 'ol') {
          if (inList) processed.push(`</${listType}>`);
          processed.push('<ol>');
          listType = 'ol';
          inList = true;
        }
        processed.push(`<li>${content}</li>`);
      }
      // 非列表行
      else {
        if (inList) {
          processed.push(`</${listType}>`);
          inList = false;
          listType = null;
        }
        processed.push(line);
      }
    }

    if (inList) {
      processed.push(`</${listType}>`);
    }

    html = processed.join('\n');

    // 12. 处理任务列表
    html = html.replace(/<li>\[ \]\s+(.+)<\/li>/g, '<li><input type="checkbox" disabled> $1</li>');
    html = html.replace(/<li>\[x\]\s+(.+)<\/li>/gi, '<li><input type="checkbox" checked disabled> $1</li>');

    // 13. 处理段落
    const paragraphLines = html.split('\n');
    const result = [];
    let inParagraph = false;
    let paragraphContent = [];

    for (let i = 0; i < paragraphLines.length; i++) {
      const line = paragraphLines[i];
      const trimmed = line.trim();

      // 空行
      if (!trimmed) {
        if (inParagraph) {
          result.push('<p>' + paragraphContent.join(' ') + '</p>');
          paragraphContent = [];
          inParagraph = false;
        }
        continue;
      }

      // 代码块占位符 - 不要包裹在段落中
      if (trimmed.match(/^<!--CODEBLOCK:\d+-->$/)) {
        if (inParagraph) {
          result.push('<p>' + paragraphContent.join(' ') + '</p>');
          paragraphContent = [];
          inParagraph = false;
        }
        result.push(line);
        continue;
      }

      // 块级元素
      if (trimmed.match(/^<(h[1-6]|pre|ul|ol|blockquote|hr|table|li)/)) {
        if (inParagraph) {
          result.push('<p>' + paragraphContent.join(' ') + '</p>');
          paragraphContent = [];
          inParagraph = false;
        }
        result.push(line);
      }
      // 块级元素结束标签
      else if (trimmed.match(/<\/(h[1-6]|pre|ul|ol|blockquote|table|li)>$/)) {
        result.push(line);
      }
      // 普通文本
      else {
        if (!inParagraph) {
          inParagraph = true;
        }
        paragraphContent.push(trimmed);
      }
    }

    if (inParagraph) {
      result.push('<p>' + paragraphContent.join(' ') + '</p>');
    }

    html = result.join('\n');

    // 14. 恢复行内代码
    html = html.replace(/<!--INLINECODE:(\d+)-->/g, (match, index) => {
      return `<code>${escapeHtml(inlineCodes[index])}</code>`;
    });

    // 15. 恢复代码块
    html = html.replace(/<!--CODEBLOCK:(\d+)-->/g, (match, index) => {
      const block = codeBlocks[index];
      const langClass = block.lang ? ` class="language-${block.lang}"` : '';
      return `<pre><code${langClass}>${escapeHtml(block.code)}</code></pre>`;
    });

    return html;
  }
};
